import java.util.*;

public int countDifferentSubsequenceGCDs(int[] nums) {
    int maximum = Arrays.stream(nums).max().getAsInt();
    int[] gcdCount = new int[maximum + 1];

    for (int num : nums) {
        for (int i = 1; i * i <= num; i++) {
            if (num % i == 0) {
                gcdCount[i]++;
                if (i * i != num) {
                    gcdCount[num / i]++;
                }
            }
        }
    }

    int differentGCDs = 0;
    for (int i = 1; i <= maximum; i++) {
        if (gcdCount[i] > 0) {
            differentGCDs++;
        }
    }

    return differentGCDs;
}
```

